const e=require("fs"),r=e.readdirSync(__dirname).filter(e=>e.endsWith(".html"));for(const n of r){let r=e.readFileSync(n,"utf8");r.includes("rgba(255, 255, 255, 0.95)")&&(r=r.replace(/background:\s*rgba\(255,\s*255,\s*255,\s*0\.95\);/g,"background: transparent;"),e.writeFileSync(n,r),console.log("Updated "+n))}console.log("Done");